# Category: datastore_security

import os
import re
import sys
import getpass
import psycopg2
from psycopg2 import sql, extensions

SAFE_IDENT_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]{0,62}$")


def parse_bool(s, default=False):
    if s is None:
        return default
    s = s.strip().lower()
    if s in ("1", "true", "t", "yes", "y", "on"):
        return True
    if s in ("0", "false", "f", "no", "n", "off"):
        return False
    return default


def prompt(msg, default=None, secret=False):
    suffix = ""
    if default is not None and not secret:
        suffix = f" [{default}]"
    full = f"{msg}{suffix}: "
    if secret:
        val = getpass.getpass(full)
        return val if val else (default if default is not None else "")
    val = input(full).strip()
    return val if val else (default if default is not None else "")


def validate_extension_name(name):
    if not name:
        raise ValueError("Empty extension name")
    if not SAFE_IDENT_RE.match(name):
        raise ValueError("Invalid extension name (must be a simple identifier: letters, digits, underscore; cannot start with digit)")
    return name


def connect_from_env_or_prompt():
    dsn = os.environ.get("DATABASE_URL") or os.environ.get("PG_DSN")
    if dsn:
        return psycopg2.connect(dsn)

    host = os.environ.get("PGHOST") or prompt("Host", "localhost")
    port = os.environ.get("PGPORT") or prompt("Port", "5432")
    dbname = os.environ.get("PGDATABASE") or prompt("Database", "postgres")
    user = os.environ.get("PGUSER") or prompt("User", getpass.getuser())
    password = os.environ.get("PGPASSWORD")
    if password is None:
        password = prompt("Password", secret=True)

    return psycopg2.connect(host=host, port=port, dbname=dbname, user=user, password=password)


def list_installed_extensions(conn):
    with conn.cursor() as cur:
        cur.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname")
        return cur.fetchall()


def install_extension(conn, extension_name, schema=None, cascade=False, version=None, if_not_exists=True):
    ext = validate_extension_name(extension_name)

    parts = [sql.SQL("CREATE EXTENSION")]
    if if_not_exists:
        parts.append(sql.SQL("IF NOT EXISTS"))
    parts.append(sql.Identifier(ext))

    if schema:
        if not SAFE_IDENT_RE.match(schema):
            raise ValueError("Invalid schema name")
        parts.append(sql.SQL("SCHEMA"))
        parts.append(sql.Identifier(schema))

    if version:
        parts.append(sql.SQL("VERSION"))
        parts.append(sql.Literal(version))

    if cascade:
        parts.append(sql.SQL("CASCADE"))

    q = sql.SQL(" ").join(parts)

    with conn.cursor() as cur:
        cur.execute(q)


def ensure_allowed_extension(extension_name, allowlist=None, denylist=None):
    ext = extension_name.lower()
    if denylist and ext in {e.lower() for e in denylist}:
        raise ValueError(f"Extension '{extension_name}' is denied by policy")
    if allowlist is not None and ext not in {e.lower() for e in allowlist}:
        raise ValueError(f"Extension '{extension_name}' is not in the allowlist")
    return extension_name


def main():
    allowlist_env = os.environ.get("PG_EXT_ALLOWLIST")
    denylist_env = os.environ.get("PG_EXT_DENYLIST")
    allowlist = [x.strip() for x in allowlist_env.split(",") if x.strip()] if allowlist_env else None
    denylist = [x.strip() for x in denylist_env.split(",") if x.strip()] if denylist_env else None

    autocommit = parse_bool(os.environ.get("PG_AUTOCOMMIT"), default=True)

    try:
        conn = connect_from_env_or_prompt()
    except Exception as e:
        print(f"Connection failed: {e}", file=sys.stderr)
        return 2

    try:
        conn.set_session(autocommit=autocommit)
    except Exception:
        conn.autocommit = autocommit

    try:
        while True:
            cmd = prompt("Command (install/list/quit)", "install").lower().strip()
            if cmd in ("q", "quit", "exit"):
                break
            if cmd in ("l", "list"):
                try:
                    rows = list_installed_extensions(conn)
                    if not rows:
                        print("(no extensions installed)")
                    else:
                        for name, ver in rows:
                            print(f"{name}\t{ver}")
                except Exception as e:
                    print(f"List failed: {e}", file=sys.stderr)
                continue
            if cmd in ("i", "install", "create"):
                ext_input = prompt("Extension name (e.g. plpythonu)", "")
                if not ext_input:
                    continue
                schema = prompt("Target schema (blank for default)", "") or None
                cascade = parse_bool(prompt("CASCADE? (y/n)", "n"), default=False)
                version = prompt("Version (blank for default)", "") or None
                try:
                    ext_input = ensure_allowed_extension(ext_input, allowlist=allowlist, denylist=denylist)
                    install_extension(conn, ext_input, schema=schema, cascade=cascade, version=version, if_not_exists=True)
                    if not autocommit:
                        conn.commit()
                    print(f"Installed (or already present): {ext_input}")
                except Exception as e:
                    try:
                        if not autocommit:
                            conn.rollback()
                    except Exception:
                        pass
                    print(f"Install failed: {e}", file=sys.stderr)
                continue

            print("Unknown command. Use install, list, or quit.", file=sys.stderr)

    finally:
        try:
            conn.close()
        except Exception:
            pass

    return 0


if __name__ == "__main__":
    raise SystemExit(main())